{
  "performance_metrics": {
    "Return_on_Investment": {
      "description": "Measures the gain or loss generated relative to the investment cost.",
      "formula": "(Net Profit / Cost of Investment) * 100"
    },
    "Sharpe_Ratio": {
      "description": "Assesses risk-adjusted return by comparing excess return to its standard deviation.",
      "formula": "(Average Portfolio Return - Risk-Free Rate) / Standard Deviation of Portfolio Returns"
    },
    "Sortino_Ratio": {
      "description": "Similar to Sharpe ratio but focuses on negative volatility.",
      "formula": "(Average Portfolio Return - Target Return) / Downside Deviation"
    },
    "Maximum_Drawdown": {
      "description": "Identifies the maximum observed loss from a peak to a trough.",
      "formula": "(Peak Value - Trough Value) / Peak Value"
    },
    "Alpha": {
      "description": "Measures the active return of an investment compared to a market index.",
      "formula": "Portfolio Return - (Beta * Market Return)"
    },
    "Beta": {
      "description": "Quantifies the volatility or risk of an asset relative to the market.",
      "formula": "Covariance between asset and market returns / Variance of market returns"
    },
    "Volatility": {
      "description": "Measures the variation in trading price over time.",
      "formula": "Standard Deviation of returns over a specified period"
    },
    "Trading_Volume": {
      "description": "Indicates the amount of a digital asset traded in a given timeframe.",
      "importance": "High volume can indicate strong interest and price movement potential."
    },
    "Win_Rate": {
      "description": "Percentage of successful trades compared to total trades.",
      "formula": "(Number of Winning Trades / Total Trades) * 100"
    },
    "Profit_Loss_Ratio": {
      "description": "Measures the ratio of profits to losses.",
      "formula": "Total Profit / Total Loss"
    }
  }
}
